<script setup>
    import { onMounted, nextTick, onUnmounted } from 'vue';
    import { gsap } from 'gsap';
    import { Power4, Back, Elastic } from 'gsap/gsap-core';
    import { MotionPathPlugin } from 'gsap/MotionPathPlugin';
    import { DrawSVGPlugin } from 'gsap/DrawSVGPlugin';
    import { ScrambleTextPlugin } from 'gsap/ScrambleTextPlugin';
    import { ArrowRight, Code2, Wrench, Layers } from 'lucide-vue-next';
    import { RouterLink } from 'vue-router';

    gsap.registerPlugin(MotionPathPlugin, DrawSVGPlugin, ScrambleTextPlugin);

    const blurbs = [
        "Experto en desarrollo web Backend y Frontend.",
        "Soluciones tecnológicas innovadoras y escalables.",
        "Enfoque en aprendizaje continuo y excelencia.",
    ];
    let curIndex = 0;
    let intervalId = null;

    const stats = [
        { value: '+2.5', label: 'años de experiencia' },
        { value: '20+', label: 'tecnologías' },
        { value: '100%', label: 'enfoque en calidad' },
    ];

    function changeTextAutomatically() {
        curIndex = (curIndex + 1) % blurbs.length;
        gsap.to(".text-container", {
            scrambleText: {
                text: blurbs[curIndex],
                chars: "upperAndLowerCase",
                revealDelay: 0.2,
                tweenLength: false
            },
            ease: "power2.inOut",
            overwrite: "auto",
            duration: 3.5
        });
    }

    onMounted(() => {
        nextTick(() => {
            gsap.set(".text-container", { autoAlpha: 1 });
            intervalId = setInterval(changeTextAutomatically, 6500);

            gsap.set(".boop", { drawSVG: "0% 1.45%", autoAlpha: 1, immediateRender: true });
            gsap.set(".boop2", { drawSVG: "98.2% 100%", autoAlpha: 1, immediateRender: true });
            gsap.set(".ball", { xPercent: -50, yPercent: -50, transformOrigin: "50%, 50%" });

            const startBall = 0.0175;
            const endBall = 0.985;
            let timeline = gsap.timeline();

            const restart = () => timeline.play(0);

            timeline
                .to(".boop", { duration: 1, ease: Power4.easeOut, drawSVG: "0% 0.2%" })
                .to(".boop", { duration: 0.6, ease: Back.easeOut.config(8), drawSVG: "0% 1.45%" }, "+=0.2")
                .to(".ball", {
                    duration: 15, ease: Elastic.easeOut.config(1, 1.2), immediateRender: true,
                    motionPath: { path: document.querySelector(".loop"), align: document.querySelector(".loop"), start: startBall, end: endBall },
                }, 1.3)
                .to(".boop2", { duration: 1, ease: Power4.easeOut, drawSVG: "99.9% 100%" }, 6.4)
                .to(".boop2", { duration: 0.6, ease: Back.easeOut.config(8), drawSVG: "98.4% 100%", delay: 0.16 }, 7.1)
                .to(".ball", {
                    duration: 15, ease: Elastic.easeOut.config(1, 1.2),
                    motionPath: { path: document.querySelector(".loop"), align: document.querySelector(".loop"), start: endBall, end: startBall },
                }, 7.3)
                .add(restart, 12.2);

            gsap.from('.hero-fade', {
                y: 24, opacity: 0, duration: 0.8, stagger: 0.12, ease: 'power3.out', delay: 0.3
            });
        });
    });

    onUnmounted(() => {
        if (intervalId) clearInterval(intervalId);
    });
</script>

